        start_npc = nil,
        start_zone = nil,
        start_pos = 'F-8',
        description = 'Mission Orders: The future that was, and the future that might have been... In revisiting the paths you walked hand in hand with Lilisette and Cait Sith, you will acquire the power needed to fulfill the will of the Goddess.',
