    ['Her Memories'] = {
        id = 40,
        start_npc = nil,
        start_zone = nil,
        start_pos = nil,
        description = 'Fragments of Lilisette\'s memories lie scattered across the land. In retracing the footsteps of her past, the way may be revealed to you.',
        reward = nil,
        fame = nil,
        fame_level = nil,
        title = nil,
